    def get(self, request):
        orders = Order.objects.filter(user=request.user)
        return Response(OrderSerializer(orders, many=True).data)

# apps/orders/selectors.py
from django.db.models import Prefetch, QuerySet
from apps.orders.models import Order, OrderItem


def order_list_for_user(
    *,
    user,
    status: str | None = None,
) -> QuerySet[Order]:
    qs = (
        Order.objects
        .filter(user=user)
        .select_related("shipping_method")
        .prefetch_related(
            Prefetch("items", queryset=OrderItem.objects.select_related("product")),
        )
        .order_by("-created_at")
    )
    if status:
        qs = qs.filter(status=status)
    return qs


# apps/orders/views.py
class OrderListView(APIView):
    def get(self, request):
        qs = order_list_for_user(user=request.user, status=request.query_params.get("status"))
        return Response(OrderSerializer(qs, many=True).data)


# apps/orders/tests/test_selectors.py
import pytest
from apps.orders.selectors import order_list_for_user


@pytest.mark.django_db
def test_order_list_for_user_query_count(django_assert_num_queries, order_factory, user_factory):
    user = user_factory()
    for _ in range(10):
        order_factory(user=user)
    with django_assert_num_queries(3):
        result = list(order_list_for_user(user=user))
        for o in result:
            list(o.items.all())  # access prefetched data
    assert len(result) == 10
